+@page "/board"
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h2 class="mb-3">Project Board</h2>
+
+@if (_loading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading…</span>
+        </div>
+    </div>
+}
+else if (_error is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @_error
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    <!-- Stats bar -->
+    <div class="row g-2 mb-3">
+        <div class="col">
+            <div class="card text-center">
+                <div class="card-body py-2">
+                    <div class="fw-bold">@_allTasks.Count</div>
+                    <small class="text-muted">Total</small>
+                </div>
+            </div>
+        </div>
+        @foreach (var col in _columns)
+        {
+            <div class="col">
+                <div class="card text-center">
+                    <div class="card-body py-2">
+                        <div class="fw-bold">@GetColumnTasks(col).Count</div>
+                        <small class="text-muted">@col</small>
+                    </div>
+                </div>
+            </div>
+        }
+        <div class="col">
+            <div class="card text-center">
+                <div class="card-body py-2">
+                    <div class="fw-bold text-danger">@_allTasks.Count(t => t.DueDate < DateTime.Today)</div>
+                    <small class="text-muted">Overdue</small>
+                </div>
+            </div>
+        </div>
+    </div>
+
+    <!-- Search bar -->
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title…"
+               @bind="_searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban columns -->
+    <div class="row g-3">
+        @for (var i = 0; i < _columns.Length; i++)
+        {
+            var colIndex = i;
+            var colName = _columns[colIndex];
+            var tasks = GetFilteredColumnTasks(colName);
+
+            <div class="col-md-4">
+                <div class="card h-100">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <strong>@colName</strong>
+                        <span class="badge bg-secondary">@tasks.Count</span>
+                    </div>
+                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height:65vh;">
+                        @foreach (var task in tasks)
+                        {
+                            <div class="card shadow-sm">
+                                <div class="card-body p-2">
+                                    <h6 class="card-title mb-1">@task.Title</h6>
+                                    <p class="mb-1 text-muted small">@task.Assignee</p>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                    </div>
+                                    <div class="d-flex gap-1">
+                                        @if (colIndex > 0)
+                                        {
+                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                    disabled="@_moving"
+                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
+                                                ← Move Left
+                                            </button>
+                                        }
+                                        @if (colIndex < _columns.Length - 1)
+                                        {
+                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                    disabled="@_moving"
+                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
+                                                Move Right →
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        <!-- Inline add-task form -->
+                        @if (_addingColumn == colName)
+                        {
+                            <div class="card border-primary">
+                                <div class="card-body p-2 d-flex flex-column gap-2">
+                                    <input type="text" class="form-control form-control-sm" placeholder="Title"
+                                           @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee"
+                                           @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm" @bind="_newPriority">
+                                        <option value="">Priority…</option>
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm flex-fill"
+                                                disabled="@_saving"
+                                                @onclick="() => SaveNewTaskAsync(colName)">
+                                            Save
+                                        </button>
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                @onclick="CancelAdd">
+                                            Cancel
+                                        </button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer text-center">
+                        <button class="btn btn-sm btn-outline-primary w-100"
+                                @onclick="() => BeginAdd(colName)">
+                            + Add Task
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private string? _error;
+    private string _searchText = string.Empty;
+    private bool _moving;
+
+    // Add-task form state
+    private string? _addingColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = string.Empty;
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+    private bool _saving;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        try
+        {
+            _loading = true;
+            _error = null;
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status)
+        => _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status)
+    {
+        var tasks = _allTasks.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(_searchText))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
+        }
+        return tasks.ToList();
+    }
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        try
+        {
+            _moving = true;
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _moving = false;
+        }
+    }
+
+    private void BeginAdd(string column)
+    {
+        _addingColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = string.Empty;
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _addingColumn = null;
+
+    private async Task SaveNewTaskAsync(string column)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle) || string.IsNullOrWhiteSpace(_newPriority))
+            return;
+
+        try
+        {
+            _saving = true;
+            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
+
+            // If the service doesn't assign the correct status, adjust it
+            var task = created.Status == column ? created : created with { Status = column };
+            if (task.Status != created.Status)
+            {
+                await TaskService.UpdateTaskStatusAsync(task.Id, column);
+            }
+
+            _allTasks.Add(task);
+            _addingColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

